import torch
import torch.nn as nn
import torchvision.transforms as transforms
from torchvision import models
from torchvision.datasets import ImageFolder
from torch.utils.data import DataLoader
import requests
import os

def download_model(url, model_name):
    response = requests.get(url)
    model_path = f"{model_name}.pt"
    with open(model_path, 'wb') as f:
        f.write(response.content)
    return model_path

def load_model(model_path, num_classes):
    model = torch.load(model_path)
    if hasattr(model, 'classifier'):
        input_features = model.classifier.in_features
        model.classifier = nn.Linear(input_features, num_classes)
    else:
        input_features = model.fc.in_features
        model.fc = nn.Linear(input_features, num_classes)
    return model

def fine_tune_model(model, train_data_dir, num_epochs, learning_rate):
    transform = transforms.Compose([
        transforms.Resize((224, 224)),
        transforms.ToTensor(),
    ])
    
    train_dataset = ImageFolder(root=train_data_dir, transform=transform)
    train_loader = DataLoader(train_dataset, batch_size=32, shuffle=True)

    criterion = nn.CrossEntropyLoss()
    optimizer = torch.optim.Adam(model.parameters(), lr=learning_rate)

    model.train()
    for epoch in range(num_epochs):
        for inputs, labels in train_loader:
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
        print(f'Epoch {epoch+1}/{num_epochs}, Loss: {loss.item()}')

# Example usage
url = 'https://path_to_pretrained_model.pt'
model_name = 'pretrained_model'
train_data_dir = 'path_to_custom_dataset'
num_classes = 10
num_epochs = 5
learning_rate = 0.001

model_path = download_model(url, model_name)
model = load_model(model_path, num_classes)
fine_tune_model(model, train_data_dir, num_epochs, learning_rate)